function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const adj: Map<number, { to: number; start: number; end: number }[]> = new Map();
    for (const [u, v, s, e] of edges) {
        if (!adj.has(u)) {
            adj.set(u, []);
        }
        adj.get(u)!.push({ to: v, start: s, end: e });
    }

    // Dijkstra's algorithm to find the minimum time to reach node n-1
    const dist: Map<number, number> = new Map();
    dist.set(0, 0);
    const pq: [number, number][] = [[0, 0]]; // [time, node]

    while (pq.length > 0) {
        const [time, node] = pq.shift()!;
        if (node === n - 1) {
            return time;
        }
        if (dist.has(node) && dist.get(node)! < time) {
            continue;
        }

        // Try to stay at the current node
        if (!dist.has(node) || time < dist.get(node)!) {
            dist.set(node, time);
            pq.push([time, node]);
        }

        // Try to take each outgoing edge
        if (adj.has(node)) {
            for (const { to, start, end } of adj.get(node)! ) {
                // Check if the edge is available at current time
                if (start <= time && time <= end) {
                    // Take the edge, time increases by 1
                    const newTime = time + 1;
                    if (!dist.has(to) || newTime < dist.get(to)!) {
                        dist.set(to, newTime);
                        pq.push([newTime, to]);
                    }
                }
            }
        }
    }

    // If we can't reach the destination
    return -1;
}

